"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";
import { MOCK_MATCHES, MOCK_ADVISORS, type MockAdvisor, type MockMatch } from "@/lib/mock-data";
import { MessageSquare, Eye, FileSignature, X, Check } from "lucide-react";

interface HydratedMatch { match: MockMatch; advisor: MockAdvisor }

function ContractFlow({ row, onClose }: { row: HydratedMatch; onClose: () => void }) {
  const [step, setStep] = useState(0);
  const [contractTitle, setContractTitle] = useState("");
  const [workDesc, setWorkDesc] = useState("");
  const [payType, setPayType] = useState<"hourly" | "fixed">("hourly");
  const [weeklyHours, setWeeklyHours] = useState("20");
  const [sent, setSent] = useState(false);

  const a = row.advisor;
  const name = [a.firstName, a.lastName].filter(Boolean).join(" ");
  const initials = ((a.firstName?.[0] || "") + (a.lastName?.[0] || "")).toUpperCase();

  if (sent) {
    return (
      <div className="fixed inset-0 z-[9100] flex items-center justify-center bg-black/40 p-4">
        <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-8 text-center space-y-4">
          <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto">
            <Check className="w-8 h-8 text-green-600" />
          </div>
          <h2 className="text-xl font-bold text-gray-900">Offer sent!</h2>
          <p className="text-gray-500 text-sm">Your offer has been sent to <strong>{name}</strong>. You'll be notified once they respond.</p>
          <button onClick={onClose} className="w-full py-2.5 bg-blue-600 text-white rounded-xl font-semibold text-sm hover:bg-blue-700 transition">
            Back to Matched CXOs
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[9100] flex items-center justify-center bg-black/40 p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[92vh]">

        {/* Header with stepper */}
        <div className="px-6 pt-5 pb-0 border-b border-gray-100">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-base font-bold text-gray-900">Start a contract</h2>
            <button onClick={onClose} className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition">
              <X className="w-4 h-4" />
            </button>
          </div>
          {/* Step progress bar */}
          <div className="flex items-center gap-0 pb-0">
            {CONTRACT_STEPS.map((s, i) => {
              const done = i < step;
              const active = i === step;
              return (
                <div key={s.id} className="flex items-center flex-1 last:flex-none">
                  <button
                    onClick={() => i < step && setStep(i)}
                    className={`flex items-center gap-2 pb-3 text-xs font-semibold border-b-2 transition whitespace-nowrap ${
                      active ? "border-blue-600 text-blue-600" :
                      done ? "border-blue-300 text-blue-400 cursor-pointer hover:text-blue-600" :
                      "border-transparent text-gray-400"
                    }`}
                  >
                    <span className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold flex-shrink-0 ${
                      done ? "bg-blue-600 text-white" :
                      active ? "bg-blue-600 text-white" :
                      "bg-gray-200 text-gray-500"
                    }`}>
                      {done ? <Check className="w-3 h-3" /> : i + 1}
                    </span>
                    {s.label}
                  </button>
                  {i < CONTRACT_STEPS.length - 1 && (
                    <ChevronRight className="w-3.5 h-3.5 text-gray-300 mx-2 flex-shrink-0 mb-3" />
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Step content */}
        <div className="flex-1 overflow-y-auto px-6 py-5 space-y-5">

          {/* Step 0: View job post */}
          {step === 0 && (
            <div className="space-y-4">
              <div className="bg-gray-50 rounded-xl p-5 space-y-3">
                <h3 className="font-semibold text-gray-900">CRO · Build a repeatable sales process</h3>
                <div className="flex flex-wrap gap-2 text-xs text-gray-500">
                  <span className="px-2 py-1 bg-white border border-gray-200 rounded-lg">Fractional · 10–20 hrs/week</span>
                  <span className="px-2 py-1 bg-white border border-gray-200 rounded-lg">Worldwide</span>
                  <span className="px-2 py-1 bg-green-50 border border-green-200 text-green-700 rounded-lg font-medium">Published</span>
                </div>
                <p className="text-sm text-gray-600">We need a senior CRO to build our outbound sales process from scratch and help us hit $2M ARR by end of year.</p>
                <div className="flex flex-wrap gap-1.5 mt-1">
                  {["Sales Process", "Revenue Operations", "Enterprise Sales"].map(s => (
                    <span key={s} className="text-xs px-2.5 py-1 bg-blue-50 text-blue-700 border border-blue-100 rounded-full">{s}</span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-3 p-3 bg-blue-50 border border-blue-100 rounded-xl text-sm text-blue-800">
                <Users className="w-4 h-4 text-blue-500 flex-shrink-0" />
                <span>This job has <strong>4 proposals</strong>. You're about to send an offer to <strong>{name}</strong>.</span>
              </div>
            </div>
          )}

          {/* Step 1: Matched CXOs */}
          {step === 1 && (
            <div className="space-y-3">
              <p className="text-sm text-gray-500">Advisors matched to this job. You're proceeding with <strong>{name}</strong>.</p>
              {[row, ...Object.values(MOCK_ADVISORS).filter(adv => {
                const n = [adv.firstName, adv.lastName].join(" ");
                return n !== name;
              }).slice(0, 2).map(adv => ({ advisor: adv, match: row.match }))].map((r, i) => {
                const adv = r.advisor;
                const n = [adv.firstName, adv.lastName].filter(Boolean).join(" ");
                const init = ((adv.firstName?.[0] || "") + (adv.lastName?.[0] || "")).toUpperCase();
                const isSelected = i === 0;
                return (
                  <div key={n + i} className={`flex items-center gap-3 p-4 rounded-xl border-2 transition ${isSelected ? "border-blue-600 bg-blue-50" : "border-gray-100 bg-white"}`}>
                    <div className="w-10 h-10 rounded-full bg-blue-600 text-white grid place-items-center font-bold text-sm flex-shrink-0">{init}</div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-semibold text-gray-900 flex items-center gap-2">
                        {n}
                        {isSelected && <span className="text-xs px-2 py-0.5 bg-blue-600 text-white rounded-full font-medium">Selected</span>}
                      </p>
                      <p className="text-xs text-gray-400 truncate">{adv.headline || "Fractional Executive"}</p>
                    </div>
                    {adv.hourlyRate && <span className="text-sm font-semibold text-gray-700 flex-shrink-0">${adv.hourlyRate}/hr</span>}
                  </div>
                );
              })}
            </div>
          )}

          {/* Step 2: Send offer */}
          {step === 2 && (
            <div className="space-y-5">
              {/* Advisor sidebar summary */}
              <div className="flex items-center gap-3 p-4 bg-gray-50 rounded-xl border border-gray-100">
                <div className="w-11 h-11 rounded-full bg-blue-600 text-white grid place-items-center font-bold flex-shrink-0">{initials}</div>
                <div>
                  <p className="text-sm font-semibold text-gray-900">{name}</p>
                  <p className="text-xs text-gray-400">{a.headline || "Fractional Executive"}</p>
                </div>
                {a.hourlyRate && <span className="ml-auto text-sm font-bold text-gray-800">${a.hourlyRate}/hr</span>}
              </div>

              {/* Job details */}
              <div className="space-y-4">
                <h3 className="text-sm font-semibold text-gray-800">Job details</h3>
                <div>
                  <label className="block text-xs font-medium text-gray-600 mb-1.5">Contract title</label>
                  <input
                    value={contractTitle}
                    onChange={e => setContractTitle(e.target.value)}
                    placeholder="e.g. Fractional CRO – Sales Process Build-out"
                    className="w-full border border-gray-200 rounded-xl px-3.5 py-2.5 text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  />
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-600 mb-1.5">Work description</label>
                  <textarea
                    rows={4}
                    value={workDesc}
                    onChange={e => setWorkDesc(e.target.value)}
                    placeholder="Set clear expectations — what you need them to accomplish and how you'll work together."
                    className="w-full border border-gray-200 rounded-xl px-3.5 py-2.5 text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent resize-none"
                  />
                  <p className="text-xs text-gray-400 mt-1 text-right">{workDesc.length}/5,000</p>
                </div>
              </div>

              {/* Contract terms */}
              <div className="space-y-4">
                <h3 className="text-sm font-semibold text-gray-800">Contract terms</h3>
                <div className="grid grid-cols-2 gap-3">
                  {[
                    { id: "hourly", label: "Pay by the hour", desc: "Pay for hours worked" },
                    { id: "fixed",  label: "Pay a fixed price", desc: "Pay a preset amount" },
                  ].map(opt => (
                    <button key={opt.id} onClick={() => setPayType(opt.id as "hourly" | "fixed")}
                      className={`text-left p-4 rounded-xl border-2 transition ${payType === opt.id ? "border-blue-600 bg-blue-50" : "border-gray-100 bg-white hover:border-blue-200"}`}>
                      <p className={`text-sm font-semibold ${payType === opt.id ? "text-blue-800" : "text-gray-800"}`}>{opt.label}</p>
                      <p className="text-xs text-gray-400 mt-0.5">{opt.desc}</p>
                    </button>
                  ))}
                </div>
                {payType === "hourly" && (
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-xs font-medium text-gray-600 mb-1.5">Hourly rate</label>
                      <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-sm">$</span>
                        <input type="number" defaultValue={a.hourlyRate || 350}
                          className="w-full border border-gray-200 rounded-xl pl-7 pr-3.5 py-2.5 text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-medium text-gray-600 mb-1.5">Weekly limit (hrs)</label>
                      <input type="number" value={weeklyHours} onChange={e => setWeeklyHours(e.target.value)}
                        className="w-full border border-gray-200 rounded-xl px-3.5 py-2.5 text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent" />
                    </div>
                  </div>
                )}
                {payType === "fixed" && (
                  <div>
                    <label className="block text-xs font-medium text-gray-600 mb-1.5">Total amount</label>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-sm">$</span>
                      <input type="number" placeholder="0"
                        className="w-full border border-gray-200 rounded-xl pl-7 pr-3.5 py-2.5 text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent" />
                    </div>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-gray-100 flex items-center justify-between">
          <button onClick={() => step === 0 ? onClose() : setStep(s => s - 1)}
            className="px-4 py-2 border border-gray-200 text-gray-600 rounded-xl text-sm font-medium hover:bg-gray-50 transition">
            {step === 0 ? "Cancel" : "← Back"}
          </button>
          {step < CONTRACT_STEPS.length - 1 ? (
            <button onClick={() => setStep(s => s + 1)}
              className="flex items-center gap-1.5 px-5 py-2 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 transition">
              Continue <ChevronRight className="w-4 h-4" />
            </button>
          ) : (
            <button onClick={() => setSent(true)}
              className="flex items-center gap-1.5 px-5 py-2 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 transition">
              <Send className="w-4 h-4" /> Send offer
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── Profile modal ────────────────────────────────────────────────────────────

function ProfileModal({ row, onClose, onMessage, onContract }: { row: HydratedMatch; onClose: () => void; onMessage: () => void; onContract: () => void }) {
  const a = row.advisor;
  const name = [a.firstName, a.lastName].filter(Boolean).join(" ");
  const initials = ((a.firstName?.[0] || "") + (a.lastName?.[0] || "")).toUpperCase();
  return (
    <div onClick={e => { if (e.target === e.currentTarget) onClose(); }}
      className="fixed inset-0 z-[9000] flex items-start justify-center bg-black/40 p-4 pt-[5vh] overflow-y-auto">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[88vh]">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <h3 className="text-base font-bold text-gray-900">Advisor profile</h3>
          <button onClick={onClose} className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition">
            <X className="w-4 h-4" />
          </button>
        </div>
        <div className="flex-1 overflow-y-auto px-6 py-5 space-y-5">
          <div className="flex items-start gap-4">
            <div className="w-16 h-16 rounded-full bg-blue-600 text-white grid place-items-center font-bold text-xl shrink-0">{initials}</div>
            <div className="min-w-0 flex-1">
              <h2 className="text-lg font-bold text-gray-900">{name}</h2>
              {a.headline && <p className="text-sm text-gray-500 mt-0.5">{a.headline}</p>}
              <div className="flex items-center gap-3 mt-1.5 text-xs text-gray-400">
                {a.city && <span>📍 {a.city}</span>}
                {a.hourlyRate && <span className="text-gray-700 font-semibold">${a.hourlyRate}/hr</span>}
              </div>
            </div>
          </div>
          {row.match.note && <Section title="Why this match"><p className="text-sm text-gray-700 leading-relaxed">{row.match.note}</p></Section>}
          {a.about && <Section title="About"><p className="text-sm text-gray-700 leading-relaxed whitespace-pre-wrap">{a.about}</p></Section>}
          {a.selectedIndustries?.length > 0 && <Section title="Industries"><Chips items={a.selectedIndustries} /></Section>}
          {a.engagementTypes?.length > 0 && <Section title="Engagement types"><Chips items={a.engagementTypes} /></Section>}
          {a.skills?.length > 0 && <Section title="Core skills"><Chips items={a.skills} gray /></Section>}
        </div>
        <div className="flex justify-end gap-2.5 px-6 py-4 border-t border-gray-100">
          <button onClick={onClose} className="px-4 py-2 border border-gray-200 text-gray-600 rounded-xl text-sm font-medium hover:bg-gray-50 transition">Close</button>
          <button onClick={onMessage} className="flex items-center gap-1.5 px-4 py-2 border border-gray-200 text-gray-700 rounded-xl text-sm font-medium hover:bg-gray-50 transition">
            <MessageSquare className="w-3.5 h-3.5" /> Send message
          </button>
          <button onClick={onContract} className="flex items-center gap-1.5 px-4 py-2 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 transition">
            <FileSignature className="w-3.5 h-3.5" /> Send an offer
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Match row ────────────────────────────────────────────────────────────────

function MatchRow({ row, onMessage, onView, onContract }: { row: HydratedMatch; onMessage: () => void; onView: () => void; onContract: () => void }) {
  const a = row.advisor;
  const name = [a.firstName, a.lastName].filter(Boolean).join(" ");
  const initials = ((a.firstName?.[0] || "") + (a.lastName?.[0] || "")).toUpperCase();
  const tags = (a.selectedRoles || []).slice(0, 3);
  return (
    <div className="bg-white border border-gray-100 rounded-2xl p-5 hover:shadow-sm transition-all">
      <div className="flex items-start gap-4">
        <button onClick={onView} className="shrink-0">
          <div className="w-14 h-14 rounded-full bg-blue-600 text-white grid place-items-center font-bold text-lg">{initials}</div>
        </button>
        <button onClick={onView} className="min-w-0 flex-1 text-left">
          <div className="text-[15px] font-semibold text-gray-900 truncate">{name}</div>
          {a.headline && <div className="text-[13px] text-gray-500 line-clamp-2 mt-0.5">{a.headline}</div>}
          <div className="flex flex-wrap items-center gap-1.5 mt-2">
            {tags.map(t => <span key={t} className="text-[11px] font-medium px-2 py-0.5 rounded-full bg-blue-50 text-blue-700 border border-blue-100">{t}</span>)}
            {a.city && <span className="text-[12px] text-gray-400 ml-1">📍 {a.city}</span>}
            {a.hourlyRate && <span className="text-[12px] font-semibold text-gray-700 ml-1">${a.hourlyRate}/hr</span>}
          </div>
          {row.match.note && (
            <div className="mt-2 text-[12.5px] text-gray-500 italic line-clamp-2">&ldquo;{row.match.note}&rdquo;</div>
          )}
        </button>

        {/* Action buttons */}
        <div className="shrink-0 flex flex-col gap-2 items-end">
          <button onClick={onContract}
            className="flex items-center gap-1.5 px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-xl hover:bg-blue-700 transition whitespace-nowrap">
            <FileSignature className="w-3.5 h-3.5" /> Send an offer
          </button>
          <div className="flex items-center gap-2">
            <button onClick={onView}
              className="flex items-center gap-1.5 px-3 py-1.5 border border-gray-200 text-gray-600 text-xs font-medium rounded-lg hover:bg-gray-50 transition">
              <Eye className="w-3.5 h-3.5" /> View details
            </button>
            <button onClick={onMessage}
              className="flex items-center gap-1.5 px-3 py-1.5 border border-gray-200 text-gray-600 text-xs font-medium rounded-lg hover:bg-gray-50 transition">
              <MessageSquare className="w-3.5 h-3.5" /> Message
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Page ─────────────────────────────────────────────────────────────────────

export default function MatchedCXOPage() {
  const router = useRouter();
  const [profileRow, setProfileRow] = useState<HydratedMatch | null>(null);

  const visible: HydratedMatch[] = MOCK_MATCHES
    .filter(m => m.status !== "archived")
    .map(m => ({ match: m, advisor: MOCK_ADVISORS[m.advisorUid] }))
    .filter(r => !!r.advisor);

  function goMessage(row: HydratedMatch) {
    router.push(`/dashboard/messages?thread=t_mock_${row.match.advisorUid}`);
  }

  function goSendOffer(row: HydratedMatch) {
    router.push(`/dashboard/send-offer?advisorId=${row.match.advisorUid}`);
  }

  return (
    <div>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Matched CXO</h1>
        <p className="text-gray-500 text-sm mt-1">Executives our team has hand-picked for your needs. Reach out or start an engagement.</p>
      </div>
      <p className="text-xs text-gray-400 mb-3">{visible.length} match{visible.length === 1 ? "" : "es"}</p>
      <div className="flex flex-col gap-3">
        {visible.map(row => (
          <MatchRow
            key={row.match.id}
            row={row}
            onMessage={() => goMessage(row)}
            onView={() => setProfileRow(row)}
            onContract={() => goSendOffer(row)}
          />
        ))}
      </div>

      {profileRow && (
        <ProfileModal
          row={profileRow}
          onClose={() => setProfileRow(null)}
          onMessage={() => { goMessage(profileRow); setProfileRow(null); }}
          onContract={() => { goSendOffer(profileRow); setProfileRow(null); }}
        />
      )}
    </div>
  );
}

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return <div className="last:mb-0"><h4 className="text-xs font-bold uppercase tracking-wider text-gray-400 mb-2">{title}</h4>{children}</div>;
}
function Chips({ items, gray }: { items: string[]; gray?: boolean }) {
  return (
    <div className="flex flex-wrap gap-1.5">
      {items.map(i => <span key={i} className={["inline-block px-2.5 py-1 rounded-full text-xs font-medium border", gray ? "bg-gray-100 border-gray-200 text-gray-700" : "bg-blue-50 border-blue-100 text-blue-700"].join(" ")}>{i}</span>)}
    </div>
  );
}
